// src/service-worker.js
import { precacheAndRoute } from 'workbox-precaching';
import { registerRoute } from 'workbox-routing';
import { CacheFirst } from 'workbox-strategies';

const INITIAL_DATA = "initial-materials-data.json";
const MATERIALS_DATA = "data/full-materials-data.json";

// Precache all assets generated by webpack
precacheAndRoute(self.__WB_MANIFEST);

// Cache the materials data
registerRoute(
  ({ url }) => url.pathname.endsWith(INITIAL_DATA),
  new CacheFirst({
    cacheName: 'materials-cache'
  })
);

self.addEventListener('activate', (event) => {
  event.waitUntil(
    Promise.all([
      caches.keys().then((cacheNames) => {
        return Promise.all(
          cacheNames
            .filter((name) => name !== 'materials-cache')
            .map((name) => caches.delete(name))
        );
      }),
      loadFullMaterialsData()
    ])
  );
});

async function loadFullMaterialsData() {
  try {
    const response = await fetch(MATERIALS_DATA);
    if (!response.ok) throw new Error("Failed to fetch full material data");

    const compressedData = await response.arrayBuffer();
    const decompressedData = await decompressData(compressedData);
    const materialData = JSON.parse(decompressedData);

    const db = await openDB();
    await updateDatabase(db, materialData);

    // Notify all clients that the full data is available
    const clients = await self.clients.matchAll();
    clients.forEach(client => {
      client.postMessage({ 
        type: 'MATERIALS_UPDATE_COMPLETE',
        timestamp: new Date().toISOString()
      });
    });
  } catch (error) {
    console.error('Error loading full material data:', error);
  }
}